The `dummy` tool is no longer available. It seems the tool list changed during this conversation. I can't make file edits with the current tools. Let me explain the situation and provide the exact changes needed.

I'm unable to edit files right now — the file editing tool that was available earlier in this conversation is no longer accessible. Here are the exact changes you need to make to `dashboard.html`:

**Change 1 — Add CSS** (after `.field-row` rule, before `/* Toast */`):

```css
  .search-select { position: relative; }
  .search-results { position: absolute; top: 100%; left: 0; right: 0; z-index: 10; background: #fff; border: 1px solid var(--rr-parchment); border-radius: 6px; box-shadow: var(--shadow-md); margin-top: 4px; max-height: 200px; overflow-y: auto; }
  .search-opt { display: flex; align-items: center; gap: 10px; padding: 8px 12px; cursor: pointer; font-family: var(--font-ui); font-size: .88rem; color: var(--rr-ink); }
  .search-opt:hover { background: var(--rr-steel-050); }
  .search-opt.selected { background: var(--rr-steel-100); font-weight: 600; }
  .search-opt .search-sub { font-family: var(--font-mono); font-size: .7rem; color: var(--rr-slate-dark); margin-left: auto; }
  .search-ava { width: 28px; height: 28px; border-radius: 999px; background: hsl(var(--primary)); color: #fff; display: flex; align-items: center; justify-content: center; font-weight: 600; font-size: .66rem; flex-shrink: 0; }
  .field-label-row { display: flex; justify-content: space-between; align-items: center; }
  .field-link { font-family: var(--font-ui); font-size: .75rem; color: hsl(var(--primary)); cursor: pointer; text-decoration: none; font-weight: 500; }
  .field-link:hover { text-decoration: underline; }
  .drawer-back { background: none; border: none; cursor: pointer; padding: 6px; color: var(--rr-slate-dark); border-radius: 4px; margin-right: 10px; display: inline-flex; align-items: center; }
  .drawer-back:hover { background: var(--rr-off-white); color: var(--rr-ink); }
```

**Change 2 — Add `NewPatientDrawer` component** (insert before `const NewAppointmentDrawer`):

```jsx
const PROVIDERS = [
  { id: 'hau', name: 'Dr Hau Le', op: 'Operatory 1' },
  { id: 'sara', name: 'Dr Sara Lim', op: 'Operatory 2' },
  { id: 'renu', name: 'Hyg. Renu', op: 'Operatory 3' },
];

const NewPatientDrawer = ({ onClose, onSave }) => {
  const [form, setForm] = React.useState({ first_name: '', last_name: '', dob: '', phone: '', email: '', insurance_provider: '', is_minor: false, guardian_name: '', consent_approved: false });
  const set = (k, v) => setForm(f => ({ ...f, [k]: v }));

  React.useEffect(() => {
    const h = e => e.key === 'Escape' && onClose();
    document.addEventListener('keydown', h);
    return () => document.removeEventListener('keydown', h);
  }, [onClose]);

  const handleSave = () => {
    const id = 'P-' + String(Math.floor(Math.random() * 90000) + 10000);
    const newPatient = { id, first: form.first_name, last: form.last_name, dob: form.dob, insurance: form.insurance_provider, last_visit: 'New', status: 'active' };
    window.PATIENTS.push(newPatient);
    onSave(newPatient);
  };

  return (
    <>
      <div className="drawer-overlay" onClick={onClose} />
      <aside className="drawer" role="dialog">
        <div className="drawer-header">
          <div style={{ display: 'flex', alignItems: 'flex-start' }}>
            <button className="drawer-back" onClick={onClose}>
              <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"><path d="m15 18-6-6 6-6"/></svg>
            </button>
            <div>
              <div className="drawer-meta">New patient</div>
              <div className="drawer-title">Register a new patient</div>
              <div className="drawer-sub">Fill in patient details. Required fields are marked.</div>
            </div>
          </div>
          <button className="drawer-x" onClick={onClose}>&times;</button>
        </div>
        <div className="drawer-body">
          <div className="field-row">
            <div className="field"><label className="lbl">First name *</label><input className="d-input" value={form.first_name} onChange={e => set('first_name', e.target.value)} /></div>
            <div className="field"><label className="lbl">Last name *</label><input className="d-input" value={form.last_name} onChange={e => set('last_name', e.target.value)} /></div>
          </div>
          <div className="field"><label className="lbl">Date of birth</label><input type="date" className="d-input" value={form.dob} onChange={e => set('dob', e.target.value)} /></div>
          <div className="field-row">
            <div className="field"><label className="lbl">Phone</label><input className="d-input" placeholder="+1 (403) 555-0000" value={form.phone} onChange={e => set('phone', e.target.value)} /></div>
            <div className="field"><label className="lbl">Email</label><input className="d-input" placeholder="patient@example.com" value={form.email} onChange={e => set('email', e.target.value)} /></div>
          </div>
          <div className="field"><label className="lbl">Insurance provider</label><input className="d-input" placeholder="Alberta Blue Cross" value={form.insurance_provider} onChange={e => set('insurance_provider', e.target.value)} /></div>
          <div className="field" style={{ flexDirection: 'row', alignItems: 'center', gap: 8 }}>
            <input type="checkbox" checked={form.is_minor} onChange={e => set('is_minor', e.target.checked)} />
            <label className="lbl" style={{ marginBottom: 0 }}>Patient is a minor</label>
          </div>
          {form.is_minor && (
            <div className="field"><label className="lbl">Guardian name</label><input className="d-input" value={form.guardian_name} onChange={e => set('guardian_name', e.target.value)} /></div>
          )}
          <div className="field" style={{ flexDirection: 'row', alignItems: 'center', gap: 8 }}>
            <input type="checkbox" checked={form.consent_approved} onChange={e => set('consent_approved', e.target.checked)} />
            <label className="lbl" style={{ marginBottom: 0 }}>Consent approved</label>
          </div>
        </div>
        <div className="drawer-footer">
          <button className="btn btn-ghost btn-md" onClick={onClose}>Back</button>
          <button className="btn btn-primary btn-md" onClick={handleSave} disabled={!form.first_name || !form.last_name}>Save patient</button>
        </div>
      </aside>
    </>
  );
};
```

**Change 3 — Replace `NewAppointmentDrawer`** with this version that uses typeahead search and the new patient flow:

```jsx
const NewAppointmentDrawer = ({ onClose, onBook }) => {
  const [patient, setPatient] = React.useState(null);
  const [patientQ, setPatientQ] = React.useState('');
  const [patientFocus, setPatientFocus] = React.useState(false);
  const [providerQ, setProviderQ] = React.useState('');
  const [provider, setProvider] = React.useState(null);
  const [providerFocus, setProviderFocus] = React.useState(false);
  const [date, setDate] = React.useState('2026-05-04');
  const [time, setTime] = React.useState('09:00');
  const [showNewPatient, setShowNewPatient] = React.useState(false);

  React.useEffect(() => {
    const h = e => { if (e.key === 'Escape' && !showNewPatient) onClose(); };
    document.addEventListener('keydown', h);
    return () => document.removeEventListener('keydown', h);
  }, [onClose, showNewPatient]);

  const filteredPatients = window.PATIENTS.filter(p =>
    !patientQ || (p.first + ' ' + p.last).toLowerCase().includes(patientQ.toLowerCase())
  );
  const filteredProviders = PROVIDERS.filter(p =>
    !providerQ || p.name.toLowerCase().includes(providerQ.toLowerCase())
  );

  const handleBook = () => {
    const name = patient ? patient.first + ' ' + patient.last : 'Unknown';
    onBook(name + ' \u00b7 ' + date + ' \u00b7 ' + time);
  };

  if (showNewPatient) {
    return <NewPatientDrawer onClose={() => setShowNewPatient(false)} onSave={(p) => { setPatient(p); setPatientQ(p.first + ' ' + p.last); setShowNewPatient(false); }} />;
  }

  return (
    <>
      <div className="drawer-overlay" onClick={onClose} />
      <aside className="drawer" role="dialog">
        <div className="drawer-header">
          <div>
            <div className="drawer-meta">New appointment</div>
            <div className="drawer-title">Book a new appointment</div>
            <div className="drawer-sub">Select patient, provider, and slot.</div>
          </div>
          <button className="drawer-x" onClick={onClose}>&times;</button>
        </div>
        <div className="drawer-body">
          <div className="field">
            <div className="field-label-row">
              <label className="lbl">Patient</label>
              <a className="field-link" onClick={() => setShowNewPatient(true)}>New patient</a>
            </div>
            <div className="search-select">
              <input className="d-input" placeholder="Type to search patients..." value={patientQ} onChange={e => { setPatientQ(e.target.value); setPatient(null); }} onFocus={() => setPatientFocus(true)} onBlur={() => setTimeout(() => setPatientFocus(false), 200)} />
              {patientFocus && filteredPatients.length > 0 && (
                <div className="search-results">
                  {filteredPatients.map(p => (
                    <div key={p.id} className={'search-opt' + (patient && patient.id === p.id ? ' selected' : '')} onMouseDown={() => { setPatient(p); setPatientQ(p.first + ' ' + p.last); setPatientFocus(false); }}>
                      <span className="search-ava">{(p.first[0] + p.last[0]).toUpperCase()}</span>
                      {p.first} {p.last}
                      <span className="search-sub">{p.id}</span>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>
          <div className="field">
            <label className="lbl">Provider</label>
            <div className="search-select">
              <input className="d-input" placeholder="Type to search providers..." value={providerQ} onChange={e => { setProviderQ(e.target.value); setProvider(null); }} onFocus={() => setProviderFocus(true)} onBlur={() => setTimeout(() => setProviderFocus(false), 200)} />
              {providerFocus && filteredProviders.length > 0 && (
                <div className="search-results">
                  {filteredProviders.map(p => (
                    <div key={p.id} className={'search-opt' + (provider && provider.id === p.id ? ' selected' : '')} onMouseDown={() => { setProvider(p); setProviderQ(p.name); setProviderFocus(false); }}>
                      {p.name}
                      <span className="search-sub">{p.op}</span>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>
          {/* rest of fields unchanged: Procedure, Date/Time, Duration, Notes */}
          <div className="field">
            <label className="lbl">Procedure</label>
            <select className="d-input" defaultValue="recall">
              <option value="recall">Recall &middot; 6mo (30 min)</option>
              <option value="crown-prep">Crown prep (60 min)</option>
              <option value="hygiene">Hygiene &middot; scaling (30 min)</option>
              <option value="implant">Implant follow-up (90 min)</option>
              <option value="composite">Composite &middot; MOD (60 min)</option>
              <option value="consult">New patient consult (30 min)</option>
              <option value="reline">Denture relines (45 min)</option>
              <option value="crown-seat">Crown seat (45 min)</option>
            </select>
          </div>
          <div className="field-row">
            <div className="field"><label className="lbl">Date</label><input type="date" className="d-input" value={date} onChange={e => setDate(e.target.value)} /></div>
            <div className="field"><label className="lbl">Time</label><input type="time" className="d-input" value={time} onChange={e => setTime(e.target.value)} /></div>
          </div>
          <div className="field">
            <label className="lbl">Duration</label>
            <select className="d-input" defaultValue="60">
              <option value="30">30 min</option>
              <option value="45">45 min</option>
              <option value="60">60 min</option>
              <option value="90">90 min</option>
            </select>
          </div>
          <div className="field">
            <label className="lbl">Notes</label>
            <textarea className="d-textarea" placeholder="Reason for visit, special instructions..." />
          </div>
        </div>
        <div className="drawer-footer">
          <button className="btn btn-ghost btn-md" onClick={onClose}>Cancel</button>
          <button className="btn btn-primary btn-md" onClick={handleBook}>Book appointment</button>
        </div>
      </aside>
    </>
  );
};
```

