            {g.items.map(it => {
              const isActive = active === it.id;
              return (
                <button key={it.id} title={collapsed ? it.name : undefined} style={{
                  width: '100%', display: 'flex', alignItems: 'center', gap: 10,
                  padding: collapsed ? '10px 0' : '8px 10px', justifyContent: collapsed ? 'center' : 'flex-start',
                  borderRadius: 4, border: 'none', background: isActive ? '#3A7FBD' : 'transparent',
                  color: isActive ? '#fff' : 'rgba(250,249,246,0.75)',
                  fontFamily: "'Inter', sans-serif", fontSize: '0.85rem', fontWeight: isActive ? 600 : 400,
                  cursor: 'pointer', transition: 'background-color 200ms ease',
                }}>
                  <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">{it.icon}</svg>
                  {!collapsed && it.name}
                </button>
              );
            })}
          </div>
        ))}
      </div>
      <div style={{ padding: '14px', borderTop: '1px solid rgba(255,255,255,0.06)', display: 'flex', alignItems: 'center', gap: 10 }}>
        <div style={{ width: 32, height: 32, borderRadius: 999, background: '#3A7FBD', display: 'flex', alignItems: 'center', justifyContent: 'center', fontWeight: 600, fontSize: '0.72rem', flexShrink: 0 }}>{userName.split(' ').map(s=>s[0]).slice(0,2).join('')}</div>
        {!collapsed && (
          <div style={{ display: 'flex', flexDirection: 'column', lineHeight: 1.2 }}>
            <span style={{ fontSize: '0.82rem' }}>{userName}</span>
            <span style={{ fontSize: '0.66rem', color: '#8A9BB0' }}>{clinicName}</span>
          </div>
        )}
      </div>
    </aside>
  );
};

Object.assign(window, { Sidebar });

// TopBar.jsx — App shell top bar with breadcrumb, ⌘K trigger, user menu

const TopBar = ({ clinicName = 'Oak Dental · Calgary', breadcrumb = ['Dashboard'] }) => (
  <header style={{
    height: 64, padding: '0 28px', background: '#fff', borderBottom: '1px solid #EDE9E0',
    display: 'flex', alignItems: 'center', justifyContent: 'space-between', position: 'sticky', top: 0, zIndex: 10,
  }}>
    <div style={{ display: 'flex', alignItems: 'center', gap: 14 }}>
      <span style={{ fontFamily: "'Montserrat', sans-serif", fontWeight: 700, fontSize: '0.9rem', color: '#0A192F', letterSpacing: '-0.01em' }}>{clinicName}</span>
      <span style={{ width: 1, height: 18, background: '#EDE9E0' }} />
      <nav style={{ display: 'inline-flex', alignItems: 'center', gap: 8, fontSize: '0.82rem', color: '#4A5568' }}>
        {breadcrumb.map((b, i) => (
          <React.Fragment key={i}>
            {i > 0 && <span style={{ color: '#C8CCCC' }}>›</span>}
            <span style={{ color: i === breadcrumb.length - 1 ? '#1C2333' : '#4A5568', fontWeight: i === breadcrumb.length - 1 ? 500 : 400 }}>{b}</span>
          </React.Fragment>
        ))}
      </nav>
    </div>
    <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
      <button style={{
        display: 'inline-flex', alignItems: 'center', gap: 8,
        background: '#FAF9F6', border: '1px solid #EDE9E0', borderRadius: 6,
        padding: '7px 12px', cursor: 'pointer', color: '#4A5568', fontFamily: "'Inter', sans-serif", fontSize: '0.82rem',
      }}>
        <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5"><circle cx="11" cy="11" r="8"/><line x1="21" y1="21" x2="16.65" y2="16.65"/></svg>
        Search
        <span style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: '0.65rem', color: '#8A9BB0', padding: '1px 6px', background: '#EDE9E0', borderRadius: 3 }}>⌘K</span>
      </button>
      <button style={{ width: 36, height: 36, borderRadius: 6, background: '#FAF9F6', border: '1px solid #EDE9E0', cursor: 'pointer', color: '#4A5568', display: 'inline-flex', alignItems: 'center', justifyContent: 'center', position: 'relative' }}>
        <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5"><path d="M18 8A6 6 0 0 0 6 8c0 7-3 9-3 9h18s-3-2-3-9"/><path d="M13.73 21a2 2 0 0 1-3.46 0"/></svg>
        <span style={{ position: 'absolute', top: 6, right: 8, width: 6, height: 6, borderRadius: 999, background: '#9B2335' }} />
      </button>
      <button style={{ width: 36, height: 36, borderRadius: 999, background: '#3A7FBD', color: '#fff', border: 'none', cursor: 'pointer', fontWeight: 600, fontSize: '0.78rem' }}>HL</button>
    </div>
  </header>
);

Object.assign(window, { TopBar });

// KpiTile.jsx — Dashboard KPI tile (label + big mono number + optional delta)

const KpiTile = ({ label, value, delta, trend = 'up', accent = 'steel' }) => {
  const accentColor = accent === 'navy' ? '#0A192F' : '#3A7FBD';
  const dColor = trend === 'up' ? '#2A7D4F' : trend === 'down' ? '#9B2335' : '#4A5568';
  const arrow = trend === 'up' ? '▲' : trend === 'down' ? '▼' : '·';
  return (
    <div style={{
      background: '#fff', border: '1px solid #EDE9E0', borderRadius: 6,
      padding: '20px 22px', boxShadow: '0 1px 2px rgba(10,25,47,0.06)',
      display: 'flex', flexDirection: 'column', gap: 6,
    }}>
      <span style={{ fontFamily: "'Inter', sans-serif", fontSize: '0.68rem', fontWeight: 600, letterSpacing: '0.12em', textTransform: 'uppercase', color: accentColor }}>
        {label}
      </span>
      <span style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: '2rem', fontWeight: 600, color: '#0A192F', letterSpacing: '-0.02em', lineHeight: 1.1 }}>
        {value}
      </span>
      {delta != null && (
        <span style={{ display: 'inline-flex', gap: 6, alignItems: 'center', fontSize: '0.78rem', color: dColor, fontWeight: 500 }}>
          <span>{arrow}</span><span>{delta}</span>
          <span style={{ color: '#8A9BB0', fontWeight: 400 }}>vs last week</span>
        </span>
      )}
    </div>
  );
};

Object.assign(window, { KpiTile });

// PatientCard.jsx — Compact patient summary card (avatar · name · DOB · insurance)

const PatientCard = ({ patient, density = 'comfortable' }) => {
  const initials = (patient.first?.[0] || '?') + (patient.last?.[0] || '?');
  const compact = density === 'compact';
  const colorByStatus = { active: '#3A7FBD', recall: '#B45309', plan: '#6BAED6', inactive: '#8A9BB0' };
  const bg = colorByStatus[patient.status] || '#3A7FBD';
  return (
    <div style={{
      background: '#fff', border: '1px solid #EDE9E0', borderRadius: 6,
      padding: compact ? '12px 14px' : '16px 18px',
      boxShadow: '0 1px 2px rgba(10,25,47,0.06)',
      display: 'grid', gridTemplateColumns: '40px 1fr auto', gap: 14, alignItems: 'center',
      cursor: 'pointer', transition: 'box-shadow 200ms ease, border-color 200ms ease',
    }}
    onMouseEnter={e => { e.currentTarget.style.boxShadow = '0 4px 20px rgba(10,25,47,0.12)'; }}
    onMouseLeave={e => { e.currentTarget.style.boxShadow = '0 1px 2px rgba(10,25,47,0.06)'; }}>
      <div style={{
        width: 40, height: 40, borderRadius: 999, background: bg, color: '#fff',
        display: 'flex', alignItems: 'center', justifyContent: 'center',
        fontFamily: "'Inter', sans-serif", fontWeight: 600, fontSize: '0.82rem',
      }}>{initials.toUpperCase()}</div>
      <div style={{ display: 'flex', flexDirection: 'column', gap: 2, minWidth: 0 }}>
        <div style={{ fontFamily: "'Inter', sans-serif", fontWeight: 600, fontSize: '0.92rem', color: '#1C2333', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
          {patient.first} {patient.last}
        </div>
        <div style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: '0.7rem', color: '#8A9BB0', display: 'flex', gap: 8 }}>
          <span>{patient.id}</span>
          <span>·</span>
          <span>{patient.dob}</span>
          <span>·</span>
          <span style={{ fontFamily: "'Inter', sans-serif", color: '#4A5568' }}>{patient.insurance}</span>
        </div>
      </div>
      <span style={{
        fontSize: '0.66rem', fontWeight: 600, padding: '3px 10px', borderRadius: 999, letterSpacing: '0.06em', textTransform: 'uppercase',
        background: patient.status === 'active' ? '#E8F5EE' : patient.status === 'recall' ? '#FDF3E5' : '#F5F2EC',
        color: patient.status === 'active' ? '#2A7D4F' : patient.status === 'recall' ? '#B45309' : '#4A5568',
      }}>{patient.status}</span>
    </div>
  );
};

Object.assign(window, { PatientCard });

// AppointmentCard.jsx — Today's appointment row (time · patient · provider · status)

const STATUS_TONE = {
  confirmed: { bg: '#E8F5EE', fg: '#2A7D4F', label: 'Confirmed' },
  pending:   { bg: '#FDF3E5', fg: '#B45309', label: 'Pending'   },
  no_show:   { bg: '#F8E5E8', fg: '#9B2335', label: 'No-show'   },
  completed: { bg: '#F5F2EC', fg: '#4A5568', label: 'Completed' },
};

const AppointmentCard = ({ appointment }) => {
  const a = appointment;
  const tone = STATUS_TONE[a.status] || STATUS_TONE.confirmed;
  const initials = a.patient.split(' ').map(s => s[0]).slice(0, 2).join('');
  return (
    <div style={{
      background: '#fff', border: '1px solid #EDE9E0', borderRadius: 6,
      padding: '14px 16px', display: 'grid',
      gridTemplateColumns: '64px 32px 1fr auto', gap: 14, alignItems: 'center',
      transition: 'box-shadow 200ms ease', cursor: 'pointer',
    }}
    onMouseEnter={e => { e.currentTarget.style.boxShadow = '0 2px 8px rgba(10,25,47,0.08)'; }}
    onMouseLeave={e => { e.currentTarget.style.boxShadow = 'none'; }}>
      <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'flex-start' }}>
        <span style={{ fontFamily: "'JetBrains Mono', monospace", fontWeight: 600, fontSize: '1rem', color: '#0A192F' }}>{a.time}</span>
        <span style={{ fontFamily: "'Inter', sans-serif", fontSize: '0.7rem', color: '#8A9BB0' }}>{a.duration} min</span>
      </div>
      <div style={{ width: 32, height: 32, borderRadius: 999, background: '#3A7FBD', color: '#fff', display: 'flex', alignItems: 'center', justifyContent: 'center', fontWeight: 600, fontSize: '0.7rem' }}>{initials.toUpperCase()}</div>
      <div style={{ display: 'flex', flexDirection: 'column', gap: 2, minWidth: 0 }}>
        <span style={{ fontFamily: "'Inter', sans-serif", fontWeight: 600, fontSize: '0.88rem', color: '#1C2333' }}>{a.patient}</span>
        <span style={{ fontFamily: "'Inter', sans-serif", fontSize: '0.74rem', color: '#4A5568' }}>{a.kind} · {a.provider} · Op {a.chair}</span>
      </div>
      <span style={{ fontSize: '0.66rem', fontWeight: 600, padding: '3px 10px', borderRadius: 4, letterSpacing: '0.06em', textTransform: 'uppercase', background: tone.bg, color: tone.fg }}>{tone.label}</span>
    </div>
  );
};

Object.assign(window, { AppointmentCard });

// LabPipeline.jsx — Lab queue Kanban (status columns: Sent · In progress · Returned · Seated)

const LAB_COLUMNS = [
  { id: 'sent',     label: 'Sent · waiting on lab',     count: 3 },
  { id: 'progress', label: 'In progress',               count: 2 },
  { id: 'returned', label: 'Returned · ready to seat',  count: 4 },
];

const LAB_CASES = [
  { id: 'LC-2026-0481', patient: 'Alice Stevens',  vendor: 'Pinnacle Dental Lab',   item: 'Crown · #36',           eta: '2026-05-12', col: 'sent'     },
  { id: 'LC-2026-0476', patient: 'Sofía Castillo', vendor: 'Crown City Lab',        item: 'Implant · #11',         eta: '2026-05-18', col: 'sent'     },
  { id: 'LC-2026-0474', patient: 'Marcus Doan',    vendor: 'Mountain Lab Services', item: 'Reline · upper denture',eta: '2026-05-08', col: 'progress' },
  { id: 'LC-2026-0469', patient: 'Priya Khanna',   vendor: 'Pinnacle Dental Lab',   item: 'Crown · #36',           eta: '2026-05-04', col: 'returned' },
  { id: 'LC-2026-0467', patient: 'Eli Brouwer',    vendor: 'Apex Ortho Lab',        item: 'Retainer',              eta: '2026-05-04', col: 'returned' },
];

const LabPipeline = () => (
  <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: 16 }}>
    {LAB_COLUMNS.map(col => {
      const cards = LAB_CASES.filter(c => c.col === col.id);
      return (
        <div key={col.id} style={{ background: '#FAF9F6', border: '1px solid #EDE9E0', borderRadius: 6, padding: 12, display: 'flex', flexDirection: 'column', gap: 8, minHeight: 240 }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '4px 6px 8px' }}>
            <span style={{ fontFamily: "'Inter', sans-serif", fontWeight: 600, fontSize: '0.7rem', letterSpacing: '0.1em', textTransform: 'uppercase', color: '#4A5568' }}>{col.label}</span>
            <span style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: '0.7rem', color: '#3A7FBD', fontWeight: 600, padding: '1px 8px', background: '#D9EAF5', borderRadius: 999 }}>{cards.length}</span>
          </div>
          {cards.map(c => (
            <div key={c.id} style={{ background: '#fff', border: '1px solid #EDE9E0', borderRadius: 6, padding: '12px 14px', display: 'flex', flexDirection: 'column', gap: 6, boxShadow: '0 1px 2px rgba(10,25,47,0.04)', cursor: 'pointer' }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', gap: 8 }}>
                <div style={{ fontFamily: "'Inter', sans-serif", fontWeight: 600, fontSize: '0.85rem', color: '#1C2333' }}>{c.patient}</div>
                <span style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: '0.66rem', color: '#8A9BB0' }}>{c.id}</span>
              </div>
              <div style={{ fontFamily: "'Inter', sans-serif", fontSize: '0.78rem', color: '#3D4D61' }}>{c.item}</div>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: 4 }}>
                <span style={{ fontFamily: "'Inter', sans-serif", fontSize: '0.7rem', color: '#4A5568' }}>{c.vendor}</span>
                <span style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: '0.7rem', color: '#B45309' }}>ETA {c.eta}</span>
              </div>
            </div>
          ))}
        </div>
      );
    })}
  </div>
);

Object.assign(window, { LabPipeline, LAB_CASES, LAB_COLUMNS });

// ToothChartTile.jsx — Compact 32-tooth chart (FDI numbering) with status fills.

const TOOTH_STATUS = {
  sound: { fill: '#fff', stroke: '#C8CCCC' },
  caries:{ fill: '#FDF3E5', stroke: '#B45309' },
  resto: { fill: '#D9EAF5', stroke: '#3A7FBD' },
  crown: { fill: '#A8CCE8', stroke: '#2E6494' },
  miss:  { fill: '#EDE9E0', stroke: '#8A9BB0' },
  endo:  { fill: '#F8E5E8', stroke: '#9B2335' },
};

// Sample marking — by tooth number (FDI quadrants 11–48, primary teeth omitted).
const MARKINGS = {
  16: 'resto', 17: 'caries', 26: 'crown', 27: 'resto',
  36: 'crown', 37: 'caries', 46: 'resto', 47: 'sound',
  31: 'sound', 41: 'sound', 11: 'sound',  21: 'sound',
  18: 'miss',  28: 'miss',  38: 'miss',  48: 'miss',
};

const ToothChartTile = () => {
  const upper = [18, 17, 16, 15, 14, 13, 12, 11, 21, 22, 23, 24, 25, 26, 27, 28];
  const lower = [48, 47, 46, 45, 44, 43, 42, 41, 31, 32, 33, 34, 35, 36, 37, 38];

  const Tooth = ({ n }) => {
    const st = MARKINGS[n] || 'sound';
    const tone = TOOTH_STATUS[st];
    return (
      <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 2 }}>
        <div style={{
          width: 22, height: 28, borderRadius: '6px 6px 3px 3px',
          background: tone.fill, border: `1.5px solid ${tone.stroke}`,
        }}/>
        <span style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: '0.6rem', color: '#8A9BB0' }}>{n}</span>
      </div>
    );
  };

  return (
    <div style={{ background: '#fff', border: '1px solid #EDE9E0', borderRadius: 6, padding: 18, boxShadow: '0 1px 2px rgba(10,25,47,0.06)' }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 12 }}>
        <span style={{ fontFamily: "'Montserrat', sans-serif", fontWeight: 700, fontSize: '0.9rem', color: '#0A192F' }}>Tooth chart</span>
        <span style={{ fontFamily: "'Inter', sans-serif", fontSize: '0.7rem', color: '#8A9BB0' }}>FDI · Updated 2026-04-21</span>
      </div>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(16, 1fr)', gap: 4, marginBottom: 8 }}>
        {upper.map(n => <Tooth key={n} n={n} />)}
      </div>
      <div style={{ height: 1, background: '#EDE9E0', margin: '8px 0' }} />
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(16, 1fr)', gap: 4 }}>
        {lower.map(n => <Tooth key={n} n={n} />)}
      </div>
      <div style={{ display: 'flex', flexWrap: 'wrap', gap: 12, marginTop: 14, fontFamily: "'Inter', sans-serif", fontSize: '0.7rem', color: '#4A5568' }}>
        {Object.entries(TOOTH_STATUS).map(([k, t]) => (
          <span key={k} style={{ display: 'inline-flex', alignItems: 'center', gap: 5 }}>
            <span style={{ width: 10, height: 10, borderRadius: 2, background: t.fill, border: `1px solid ${t.stroke}` }} /> {k}
          </span>
        ))}
      </div>
    </div>
  );
};

Object.assign(window, { ToothChartTile });

