/*
 * Rockyridge Dental AI — Design System Tokens
 * colors_and_type.css
 *
 * A blend of shadcn/ui semantic token shape (HSL channel triplets, light/dark scopes)
 * with the Rockyridge AI Solutions brand language (Montserrat display + Inter UI,
 * Navy / Steel / Warm-white palette, sweep-fill button motif).
 *
 * Light theme (`:root`) is the default for all clinical/admin surfaces.
 * Dark theme (`.dark`) is reserved for the login portal and any marketing
 * hero sections that mirror the parent rockyridgeai.com aesthetic.
 *
 * Structure:
 *   1. Brand raw scales (navy, steel, neutral)               — single source of truth
 *   2. Shadcn HSL semantic tokens (light)                    — :root
 *   3. Shadcn HSL semantic tokens (dark — login portal)      — .dark
 *   4. Typography tokens                                     — fonts, scale, leading
 *   5. Spacing / radius / shadow / motion                    — geometry
 *   6. Element defaults (body, headings, code, link, etc.)
 *   7. Sweep-button utilities (RR signature interaction)
 */

@import url('https://fonts.googleapis.com/css2?family=Montserrat:ital,wght@0,400;0,500;0,600;0,700;0,800;0,900;1,700&family=Inter:wght@300;400;500;600;700&family=JetBrains+Mono:wght@400;500;600&display=swap');

/* ─────────────────────────────────────────────
   1. BRAND RAW SCALES
   ───────────────────────────────────────────── */
:root {
  /* Navy — primary brand identity (parent: rockyridgeai.com) */
  --rr-navy-900: #060F1E;
  --rr-navy-800: #0A192F;   /* brand navy — logo fill */
  --rr-navy-700: #0D2137;
  --rr-navy-600: #112940;
  --rr-navy-500: #1D3461;
  --rr-navy-400: #2B4A7C;
  --rr-navy-300: #3D6494;

  /* Steel Blue — action / accent */
  --rr-steel-700: #234C70;
  --rr-steel-600: #2E6494;
  --rr-steel-500: #3A7FBD;  /* primary action */
  --rr-steel-400: #4A90D4;
  --rr-steel-300: #6BAED6;
  --rr-steel-200: #A8CCE8;
  --rr-steel-100: #D9EAF5;
  --rr-steel-050: #EEF6FB;

  /* Neutral surfaces */
  --rr-warm-white: #FAF9F6;
  --rr-off-white:  #F5F2EC;
  --rr-parchment:  #EDE9E0;
  --rr-silver:     #E0E0E0;
  --rr-mist:       #C8CCCC;
  --rr-slate:      #8A9BB0;
  --rr-slate-dark: #4A5568;

  /* Ink */
  --rr-ink:        #1C2333;
  --rr-ink-light:  #3D4D61;

  /* Semantic functional */
  --rr-success:    #2A7D4F;
  --rr-success-bg: #E8F5EE;
  --rr-warning:    #B45309;
  --rr-warning-bg: #FDF3E5;
  --rr-error:      #9B2335;
  --rr-error-bg:   #F8E5E8;
  --rr-info:       #3A7FBD;
  --rr-info-bg:    #D9EAF5;

  /* ─────────────────────────────────────────────
     2. SHADCN SEMANTIC TOKENS — LIGHT (default)
     HSL channel triplets so Tailwind's hsl(var(--…)) works.
     Kept in *exact* shadcn variable names so component code
