  .d-input { font-family: var(--font-ui); font-size: .9rem; padding: 10px 12px; border: 1.5px solid var(--rr-mist); border-radius: 6px; width: 100%; box-sizing: border-box; background: #fff; color: var(--rr-ink); }
  .d-input:focus { border-color: hsl(var(--ring)); box-shadow: var(--shadow-ring); outline: none; }
  .d-textarea { font-family: var(--font-ui); font-size: .9rem; padding: 10px 12px; border: 1.5px solid var(--rr-mist); border-radius: 6px; width: 100%; box-sizing: border-box; min-height: 80px; resize: vertical; background: #fff; color: var(--rr-ink); }
  .d-textarea:focus { border-color: hsl(var(--ring)); box-shadow: var(--shadow-ring); outline: none; }
