old = "  .field-row { display: grid; grid-template-columns: 1fr 1fr; gap: 14px; }\n\n  /* Toast */"
new = """  .field-row { display: grid; grid-template-columns: 1fr 1fr; gap: 14px; }

  /* Typeahead search select */
  .search-select { position: relative; }
  .search-select .d-input { padding-right: 32px; }
