  .search-opt.selected { background: var(--rr-steel-100); font-weight: 600; }
  .search-opt .search-sub { font-family: var(--font-mono); font-size: .7rem; color: var(--rr-slate-dark); margin-left: auto; }
  .search-ava { width: 28px; height: 28px; border-radius: 999px; background: hsl(var(--primary)); color: #fff; display: flex; align-items: center; justify-content: center; font-weight: 600; font-size: .66rem; flex-shrink: 0; }
