  .field-link { font-family: var(--font-ui); font-size: .75rem; color: hsl(var(--primary)); cursor: pointer; text-decoration: none; font-weight: 500; }
  .field-link:hover { text-decoration: underline; }
  .drawer-back { background: none; border: none; cursor: pointer; padding: 6px; color: var(--rr-slate-dark); border-radius: 4px; margin-right: 10px; display: inline-flex; align-items: center; }
  .drawer-back:hover { background: var(--rr-off-white); color: var(--rr-ink); }

  /* Toast */"""

assert old in c, "Pattern not found"
c = c.replace(old, new, 1)
with open(path, 'w') as f:
    f.write(c)
print("OK")
